var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후우…… 최고 관리자 회의를 앞두고 뒤숭숭한 마당에 기어코 일을 벌였군.","JPN":"ふう……最高管理者会議の前で浮足立っているときに、やらかしてくれたな。","ENG":"*Sigh...* You just had to cause trouble right before the Supreme Administrator meeting.","TWN":"哀……最高管理者會議召開前夕亂哄哄的，硬要挑這個時候惹事嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이번 일은 조용히 넘어갈 수 없어. 한동안 정보부가 시끄러울 거야.","JPN":"今度のことは伏せられないだろう。しばらくは情報部がうるさくなる。","ENG":"This one won't slide under the radar. The Intelligence Agency is going to be all over it.","TWN":"這次的事沒辦法就這樣含糊帶過，情報部這一陣子應該會很熱鬧。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아이들은 확실히 단속하게. 비슷한 일이 다시 벌어지면 그 때는 나도 뒤를 봐 줄 수 없어.","JPN":"子どもたちはしっかり管理してくれよ。また似たようなことが発生すると、その時には私もフォローできない。","ENG":"Don't let those kids out of your sight. If something like this happens again, I won't be able to cover for you.","TWN":"把那些孩子管好，下次要是再發生類似的事，到時候恐怕我也無能為力。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어휴, 저 양반은 또 오므라이스 먹고 있네. 세 끼 전부 오므라이스로 떼우겠어, 아주.","JPN":"もう、あの人はまたオムライス食べてる。三食全部オムライスになるかもしれないわ、まったく。","ENG":"Ugh... Is he eating that kids' meal again? Is fried rice omelet all he ever eats?","TWN":"真是的，那位先生又在吃蛋包飯，看來三餐都要吃蛋包飯囉。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아무튼 그렇게 됐어. 도로시 네 다리는 좀 나중에 수리해야겠다.","JPN":"とにかく、そういうことで。ドロシー、あんたの足は後で修理することになるわね。","ENG":"Anyway, it is what it is. Guess we'll have to get your legs repaired another day.","TWN":"總之就是這樣，桃樂絲你的腿可能要之後才能修理。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"헴스워스 할아버지를 부르면 안 돼?","JPN":"ヘムズワースお爺さんを呼んじゃダメなの？","ENG":"Can't we just call Helmsworth?","TWN":"不能找漢姆沃斯爺爺嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그 할아버지가 부른다고 와 줄까.","JPN":"呼んだところで、あのお爺さんが来てくれるかな。","ENG":"Do you think he'll come just because you called?","TWN":"要找那個爺爺來嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"안 돼. 토토를 해체하려고 할지도 몰라.","JPN":"ダメ。トトを解体しようとするかもしれないよ。","ENG":"No. He might try to dissect Toto.","TWN":"不要，他可能會想把托托解體。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 조금 늦어져도 괜찮아. 당분간 달릴 일은 없을 것 같거든.","JPN":"ま、少し遅くなっても大丈夫。しばらく走ることはなさそうだからね。","ENG":"Eh, I don't mind if it's a little later. I don't think I'll have to run for a while anyway.","TWN":"沒關係啦，晚點修也可以，暫時也沒什麼需要奔跑的事吧。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흥. 그러시겠지. 위원회 코털을 건드리는 대형 사고까지 쳤는걸.","JPN":"ふん。そうでしょうとも。委員会の機嫌を損ねる大事故までやらかしたんだから。","ENG":"Hmph. You said it. Causing a major incident that even the committee is interested in.","TWN":"哼，是吧，這可是觸碰到委員會敏感神經的大型事故。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"리코리스도 같이 건드렸어.","JPN":"リコリスも一緒にやらかした。","ENG":"You're part of it too, Lycoris.","TWN":"莉克麗絲也有一起觸碰。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"맞아. 우린 공범이야.","JPN":"そうだよ。私たちは共犯なの。","ENG":"Yeah, you're our accomplice.","TWN":"對啊，我們是共犯。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"난 이미 한 건 걸려 있단 말이야! 블랙 네트워크에서 수배서 보고 얼마나 기겁했는데!","JPN":"私はすでに一件あるのよ！　ブラックネットワークで手配書見てどれだけビックリしたと思ってるの！？","ENG":"Well, this is my strike two, okay?! Do you know how horrified I was to see my bounties posted on the Dark Network?!","TWN":"我早就被記一筆啦！在黑色網路看到通緝令時我有多震驚！"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아아…… 내가 못 살아, 진짜.","JPN":"ああ……イヤだわ、もう。","ENG":"Ugh... You're going to drive me crazy.","TWN":"吼……我真的會氣死。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런데 우리는 이제 어떻게 되는 거야? 관리국의 현장 요원으로 구른다거나?","JPN":"ところで、私たちはこれからどうなるの？　管理局の現場要員として使われるとか？","ENG":"So, what happens to us now? Are we now field agents of the Administration?","TWN":"那我們現在該怎麼辦？去當管理局的幹員嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"가출 청소년에게 손 벌릴 만큼 관리국이 만만하진 않거든? 나 같은 말단이랑 좀 어울렸다고 콧대만 높아져선.","JPN":"家出した青少年を雇ってくれるほど管理局は甘くないのよ。私みたいな末端と付き合ったからって偉ぶっちゃって。","ENG":"What, you think you're a big deal now because you hang out with a low-level agent like me? Or did you really believe the Administration would hire some runaway kids as field agents?","TWN":"管理局可沒有好欺負到會向離家出走的青少年伸出手，他們都是用鼻孔在看我們這種基層人員的。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 하하. 그런가…….","JPN":"あ、はは。そっか……","ENG":"Ah, hah hah. Did I?","TWN":"哈哈，是喔……"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"일단 정보부를 통해서 세이프 하우스를 하나 쓸 계획이야.","JPN":"一応は情報部を通じてセーフハウスを一軒借りる予定よ。","ENG":"For now, we're planning to use a safehouse provided by the Intelligence Agency.","TWN":"總之我打算先透過情報部弄到一個安全的藏身處。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그리고…… 리온, 네 경우에는 아카데미로 가는 편이 좋겠어.","JPN":"それから……リオン、あんたはアカデミーに行った方がいいね。","ENG":"And... Liona? I think you should go to the Academy.","TWN":"然後……萊恩，你的話去學院比較合適。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 아카데미? 카운터 아카데미 말이야?","JPN":"あ、アカデミー？　カウンターアカデミーのこと？","ENG":"Th-the Academy? You mean the Counter Academy?","TWN":"學…學院？你是說制裁者學院嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그래. 거기서 지내면 평의회도 함부로 건드리지 못할 거야.","JPN":"そう。あそこなら評議会も簡単に手を出せないはずよ。","ENG":"Yeah. If you're there, The Dark Council won't be able to harm you.","TWN":"沒錯，你在那的話，評議會也不敢輕易動你。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하지만…… 난 친구들이랑…….","JPN":"でも……私は友達と……","ENG":"But... I want to...","TWN":"可是……我想和朋友……"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"왜. 좋네, 아카데미.","JPN":"何よ。いいじゃない、アカデミー。","ENG":"What's the matter? The Academy sounds great.","TWN":"幹嘛這樣，學院很好啊。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"한동안 가출 생활을 했으니까, 학교에 다시 다니려면 고생 좀 하겠다.","JPN":"結構長く家出してるから、また学校に通うとなると苦労しそうだ。","ENG":"You've been out on the streets for such a long time, it might take some time to get readjusted to school.","TWN":"畢竟已經離家出走一陣子，要重回校園會有點辛苦。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"괘, 괜찮겠어? 너희들?","JPN":"み、みんなは大丈夫なの？","ENG":"A-are you all sure about this?","TWN":"你…你們沒關係嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"난 오히려 네가 더 걱정인데. 토토랑 같이 다니면 하루하루가 고생일걸.","JPN":"私はむしろリオンが心配なんだけど。トトと一緒にいると毎日苦労しそうだ。","ENG":"Well, I'm more worried about you. Every day's gonna be tough if you take Toto with you.","TWN":"我才擔心你咧，和托托一起每天都很辛苦吧。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도로시 말에 동의해. 응원은 해 줄게.","JPN":"ワタシもドロシーと同じ意見だ。応援はしてあげる。","ENG":"I agree with Dorothy. But I'll root for you.","TWN":"同意桃樂絲，你加油。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐래. 너희들도 다시 학교 갈 준비나 해야지.","JPN":"何言ってるの。あんたたちもまた学校に通う準備しなさい。","ENG":"Huh? You're going back to school, too.","TWN":"在說什麼，你們也都準備回學校去。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어? 우, 우리도?","JPN":"え？　わ、私たちも？","ENG":"W-what? Us too?","TWN":"什麼？我們也要？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"영문을 모르겠네. 우리는 나이만 어리지 닳고 닳은 사회인이야.","JPN":"わけがわからない。ワタシたちは年が若いだけで、本当はすっかりすれた社会人だよ。","ENG":"I don't understand. We might be young, but we're practically adults now.","TWN":"不明白，我們只是年紀小，但可是經過社會磨練的社會人士。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어른들은 다들 어린애로 돌아가고 싶어해. 어른이라고 자부하는 시점에서 이미 애거든?","JPN":"大人はみんな子どもに戻りたがるものなの。大人だと主張する時点でまだ子どもだってこと。","ENG":"All adults want to go back to the time of their childhood. Calling yourself an adult just means you're still a kid.","TWN":"大人都想變回小孩子，只有小孩才會說自己是大人好嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그러니까, 애들은 애들답게 학교나 열심히 다녀.","JPN":"だから、子どもは子どもらしく一生懸命学校に通いなさいね。","ENG":"Anyway, kids should act like kids and go to school.","TWN":"所以你們就做小孩該做的事，乖乖回學校認真讀書吧。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"저기, 일단 저는 학교랑 인연이 좀 없는데요.","JPN":"あの、一応私は学校とは縁がないんですけど。","ENG":"Well, I'm past school age.","TWN":"那個，我和學校沒什麼緣分。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그렇네. 메이드복 관심 있어?","JPN":"確かにそうね。メイド服、興味ない？","ENG":"Oh, right. Are you interested in wearing a maid uniform?","TWN":"對欸，那你對女僕裝有興趣嗎？"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"대학교 진학을 노려 보겠습니다!","JPN":"大学校の進学を目指してみます！","ENG":"I'll do my best to get into college!","TWN":"我會努力考上大學！"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};